503	/// Render one record cell from its flat (un-escaped) text into the exact label
504	/// bytes: single line (escaped) when it fits [`FILL_WIDTH`], otherwise the wrapped
505	/// form — physical lines each prefixed by their `&nbsp;` indent, escaped, and
506	/// terminated by `\l` (trailing `\l` included), per BEHAVIOR.md §3f.
507	///
508	/// Dispatch by cell shape: an info cell (`#t : Rule[…]`) uses the vertical action
509	/// `sep`; a fact / relation cell (`NAME( … )`) uses the greedy argument/tuple fill
510	/// with the delimiter peel. The same entry serves the Term-based path (feed
511	/// [`Fact::render_flat`]) and the pre-rendered-string path (feed the caller's
512	/// already-rendered cell text): the wrap and escape apply identically.
513	pub fn wrap_cell(flat: &str) -> String {
514	    wrap_cell_budget(flat, FILL_WIDTH)
515	}
516	
517	/// Render one record cell with an explicit wrap `budget` (BEHAVIOR.md §3f). The
518	/// budget is the cell's share of its record group's [`FILL_WIDTH`] — see
519	/// [`cell_budget`]; a lone cell uses [`FILL_WIDTH`]. An info cell (`#t : Rule[…]`)
520	/// uses the vertical action `sep` (always vertical for ≥ 2 actions); a fact /
521	/// relation cell (`NAME( … )`) uses the greedy argument/tuple fill with the
522	/// delimiter peel. This is the single entry for both the Term-based path (feed
523	/// [`Fact::render_flat`]) and the pre-rendered-string path.
524	pub fn wrap_cell_budget(flat: &str, budget: usize) -> String {
525	    let lines = if flat.starts_with('#') && flat.contains('[') {
526	        layout_info(flat, budget)
527	    } else {
528	        layout_fact(flat, budget)
529	    };
530	    if lines.len() == 1 && lines[0].0 == 0 {
531	        return escape_record(&lines[0].1);
532	    }
533	    let mut out = String::new();
534	    for (indent, text) in &lines {
535	        out.push_str(&"&nbsp;".repeat(*indent));
536	        out.push_str(&escape_record(text));
537	        out.push_str("\\l");
538	    }
539	    out
540	}
