#!/usr/bin/env python3
import re, glob, sys
CORP="/home/kamilner/tamarin-cleanroom/graphdot/oracle/dot_corpus"

def split_top(s, opench='{', closech='}', sep='|'):
    # split s on top-level `sep`, honoring {} nesting and backslash-escapes; also skip () <> [] ? 
    # For record label group split we only need brace + pipe with escape awareness.
    parts=[]; depth=0; cur=[]; i=0
    while i < len(s):
        c=s[i]
        if c=='\\' and i+1<len(s):
            cur.append(s[i:i+2]); i+=2; continue
        if c=='{': depth+=1; cur.append(c)
        elif c=='}': depth-=1; cur.append(c)
        elif c==sep and depth==0:
            parts.append(''.join(cur)); cur=[]
        else: cur.append(c)
        i+=1
    parts.append(''.join(cur))
    return parts

def flat_width(cell):
    # cell text after "<nK> " (may contain \l, &nbsp;, escapes). Reconstruct flat visual width.
    lost = len(re.findall(r',\\l', cell)) + len(re.findall(r'\\l\)', cell))
    t = cell.replace('\\l','')
    t = t.replace('&nbsp;','')
    # unescape record metachars to 1 visual col each
    for a,b in [('\\<','<'),('\\>','>'),('\\{','{'),('\\}','}'),('\\|','|')]:
        t=t.replace(a,b)
    return len(t) + lost

def count_actions(infocell):
    # infocell flat-ish; count top-level actions in [...]
    b=infocell.replace('\\l','')
    b=b.replace('&nbsp;','')
    for a,x in [('\\<','<'),('\\>','>'),('\\|','|'),('\\{','{'),('\\}','}')]: b=b.replace(a,x)
    i=b.find('[')
    if i<0: return 0
    if i+1<len(b) and b[i+1]==']': return 0
    depth=0; acts=1; j=i+1
    while j<len(b):
        c=b[j]
        if c in '(<[': depth+=1
        elif c==']' and depth==0: break
        elif c in ')>': depth-=1
        elif c==',' and depth==0: acts+=1
        j+=1
    return acts

def parse_record(label):
    # label = {grp|grp|grp} ; strip outer braces
    assert label.startswith('{') and label.endswith('}')
    inner=label[1:-1]
    groups=split_top(inner)  # each is like {cell|cell}
    parsed=[]
    for g in groups:
        g=g.strip()
        if not (g.startswith('{') and g.endswith('}')): 
            return None
        cells=split_top(g[1:-1])
        # each cell: "<nK> TEXT"
        texts=[]
        for c in cells:
            m=re.match(r'<n\d+> (.*)$', c, re.S)
            if not m: return None
            texts.append(m.group(1))
        parsed.append(texts)
    return parsed

def is_info_group(cells):
    return len(cells)==1 and re.match(r'#\S+ : ', cells[0])

total_cells=0; mism=0; examples=[]
nrec=0
files=sorted(glob.glob(CORP+"/*.dot"))
for f in files:
    for line in open(f):
        if 'shape="record"' not in line: continue
        m=re.search(r'label="(.*)",fillcolor', line)
        if not m: continue
        lab=m.group(1)
        try:
            groups=parse_record(lab)
        except Exception:
            groups=None
        if groups is None: 
            continue
        nrec+=1
        for gi,cells in enumerate(groups):
            info = is_info_group(cells)
            if info:
                cell=cells[0]
                actual = '\\l' in cell
                nact = count_actions(cell)
                fw = flat_width(cell)
                pred = (nact>=2) or (fw>87)
                total_cells+=1
                if pred!=actual:
                    mism+=1
                    if len(examples)<12: examples.append((f.split('/')[-1],'INFO',nact,fw,pred,actual,cell[:80]))
            else:
                flats=[flat_width(c) for c in cells]
                T=sum(flats)
                for c,fw in zip(cells,flats):
                    actual = '\\l' in c
                    pred = (T>87) and (fw>20)
                    total_cells+=1
                    if pred!=actual:
                        mism+=1
                        if len(examples)<12: examples.append((f.split('/')[-1],f'grp{gi}',T,fw,pred,actual,c[:80]))
print(f"records parsed: {nrec}, cells checked: {total_cells}, MISMATCHES: {mism} ({100*mism/max(total_cells,1):.4f}%)")
for e in examples:
    print("  MISMATCH", e[:6], repr(e[6]))

