460	/// Assemble a record node's model from a [`RecordSpec`] and its allocated ports.
461	/// Empty premise / conclusion groups are dropped; the info group is always kept
462	/// (matches the observed group structure). Each group's cells share the record
463	/// wrap budget: within a premise or conclusion group a cell wraps when its flat
464	/// width exceeds `max(87 − Σ other cell flats, 20)` (BEHAVIOR.md §3f); the info
465	/// cell is its own single-cell group (budget 87). Cell text is wrapped and escaped
466	/// by [`wrap_cell_budget`].
467	fn build_record(spec: &RecordSpec, ports_prem: &[String], port_info: &str, ports_concl: &[String]) -> Record {
468	    let mut columns: Vec<Vec<Cell>> = Vec::new();
469	    if !spec.premises.is_empty() {
470	        columns.push(group_cells(&spec.premises, ports_prem));
471	    }
472	    columns.push(vec![Cell::new(port_info, wrap_cell(&spec.info))]);
473	    if !spec.conclusions.is_empty() {
474	        columns.push(group_cells(&spec.conclusions, ports_concl));
475	    }
476	    Record {
477	        columns,
478	        fillcolor: spec.fillcolor.clone(),
479	        fontcolor: spec.fontcolor.clone(),
480	        role: Role(spec.role.clone()),
481	    }
482	}
483	
484	/// Wrap every cell of one record group (all premises together, or all conclusions
485	/// together), sharing the group budget: each cell's budget is [`cell_budget`] over
486	/// the group's flat cell widths, so a cell wraps only when the group total exceeds
487	/// the fill width (BEHAVIOR.md §3f).
488	fn group_cells(flat_cells: &[String], ports: &[String]) -> Vec<Cell> {
489	    let widths: Vec<usize> = flat_cells.iter().map(|t| t.chars().count()).collect();
490	    flat_cells
491	        .iter()
492	        .zip(ports)
493	        .enumerate()
494	        .map(|(i, (text, p))| Cell::new(p.clone(), wrap_cell_budget(text, cell_budget(&widths, i))))
495	        .collect()
496	}
497	
498	/// Resolve an [`EndRef`] to a serializer [`EndPoint`] using the id/port map.
499	fn endpoint(resolved: &[Resolved], r: EndRef) -> EndPoint {
500	    match r {
501	        EndRef::Whole(n) => EndPoint::node(resolved[n].node_id().to_string()),
502	        EndRef::Conclusion(n, c) => {
503	            if let Resolved::Record { node, ports_concl, .. } = &resolved[n] {
504	                EndPoint::port(node.clone(), ports_concl[c].clone())
505	            } else {
506	                EndPoint::node(resolved[n].node_id().to_string())
507	            }
508	        }
509	        EndRef::Premise(n, p) => {
510	            if let Resolved::Record { node, ports_prem, .. } = &resolved[n] {
511	                EndPoint::port(node.clone(), ports_prem[p].clone())
512	            } else {
513	                EndPoint::node(resolved[n].node_id().to_string())
514	            }
515	        }
516	    }
517	}
