/// Wrap every cell of one record group (all premises together, or all conclusions
/// together), sharing the group's [`FILL_WIDTH`] budget (BEHAVIOR.md §3f).
///
/// Two budgets per cell, both derived from the group's cell widths:
///  * the **wrap TRIGGER** (does a cell break at all) is the flat-sum budget
///    [`cell_budget`] = `max(87 − Σ other cells' flat widths, 20)`: a cell wraps
///    iff its flat width exceeds this. This is byte-exact away from the ±1 `fits`
///    boundary (matches 99.5 % of corpus cells).
///  * the **FILL width** used *once* a cell wraps is the cell's share of what its
///    siblings actually OCCUPY, not their flat widths. Sibling cells that wrap take
///    less room than their flat width, so a cell packs more per line than the
///    flat-sum budget alone predicts (the observed "one more element" in a group
///    like `[Ack 25, Big 68, Out 14]`, where `Big`'s effective fill budget is
///    `87 − occ(Ack)=17 − occ(Out)=14 = 56`, not `87 − 25 − 14 = 48`).
///
/// The fill widths come from a **smallest-flat-first** allocation that reproduces
/// the greedy pretty-printer's coupling: process cells in increasing flat width;
/// each cell's fill budget is `max(87 − Σ others' occupied widths, 20)` where an
/// already-processed sibling contributes its wrapped [`cell_occ`] and an
/// un-processed (wider) sibling contributes its full flat width; then the cell's
/// own occupied width is fixed by laying it out at that budget. So narrow cells are
/// packed tight first and the widest cell expands into the room they free.
fn group_cells(flat_cells: &[String], ports: &[String]) -> Vec<Cell> {
    let widths: Vec<usize> = flat_cells.iter().map(|t| t.chars().count()).collect();
    let n = flat_cells.len();
    let trigger: Vec<usize> = (0..n).map(|i| cell_budget(&widths, i)).collect();

    // Smallest-flat-first fill-budget allocation. `occ[j]` starts at the flat width
    // and is replaced by the cell's wrapped occupied width once it is processed.
    let mut order: Vec<usize> = (0..n).collect();
    order.sort_by_key(|&i| widths[i]); // stable: ties keep group order
    let mut occ = widths.clone();
    let mut fill = vec![0usize; n];
    for &i in &order {
        let others_occ: usize = (0..n).filter(|&j| j != i).map(|j| occ[j]).sum();
        let budget = FILL_WIDTH.saturating_sub(others_occ).max(MIN_CELL_BUDGET);
        fill[i] = budget;
        occ[i] = cell_occ(&flat_cells[i], budget);
    }

    flat_cells
        .iter()
        .zip(ports)
        .enumerate()
        .map(|(i, (text, p))| {
            // The flat-sum trigger decides whether the cell breaks; the fill budget
            // (≥ the trigger budget) governs how it packs once it does. Capping at
            // `flat − 1` keeps a flat-sum-triggered break even in the rare case the
            // wider fill budget alone would leave the cell on one line.
            let budget = if widths[i] <= trigger[i] {
                trigger[i]
            } else {
                fill[i].min(widths[i] - 1).max(trigger[i])
            };
            Cell::new(p.clone(), wrap_cell_budget(text, budget))
        })
        .collect()
}

