/// The occupied width of a cell laid out at `budget` (BEHAVIOR.md §3f): the widest
/// physical line, counting its `&nbsp;` indent column plus its text. Equals the
/// flat width when the cell does not wrap. This is the width a sibling cell
/// *actually takes* once wrapped — narrower than its flat width — which is what a
/// neighbouring cell's fill budget is measured against (see the group fill-budget
/// allocation in [`crate::generate`]): a wide cell that wraps to a narrow tuple
/// line (e.g. `Ack( ~n.4, <x1.4, x2.4> )` → occupied 17, not flat 25) frees space
/// for its siblings' fill accordingly.
pub fn cell_occ(flat: &str, budget: usize) -> usize {
    layout_cell(flat, budget)
        .iter()
        .map(|(indent, text)| indent + width(text))
        .max()
        .unwrap_or(0)
}

